begin;
alter table public.meetings add column if not exists reminder_at timestamptz;
create table if not exists public.push_subscriptions(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,endpoint text not null unique,p256dh text not null,auth_key text not null,user_agent text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.notification_deliveries(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,source_type text not null,source_id uuid not null,scheduled_for timestamptz not null,sent_at timestamptz,status text not null default 'pending' check(status in('pending','sent','failed')),error text,created_at timestamptz not null default now(),unique(user_id,source_type,source_id,scheduled_for));
create index if not exists push_subscriptions_user on public.push_subscriptions(user_id);create index if not exists notification_deliveries_schedule on public.notification_deliveries(status,scheduled_for);create index if not exists meetings_reminder on public.meetings(reminder_at) where archived_at is null and reminder_at is not null;create index if not exists tasks_reminder on public.tasks(reminder_at) where archived_at is null and reminder_at is not null;
alter table public.push_subscriptions enable row level security;alter table public.notification_deliveries enable row level security;grant select,insert,update,delete on public.push_subscriptions to authenticated;grant select on public.notification_deliveries to authenticated;revoke all on public.push_subscriptions,public.notification_deliveries from anon;
create policy push_subscriptions_select on public.push_subscriptions for select to authenticated using((select auth.uid())=user_id and (select private.is_workspace_member(workspace_id)));
create policy push_subscriptions_insert on public.push_subscriptions for insert to authenticated with check((select auth.uid())=user_id and (select private.is_workspace_member(workspace_id)));
create policy push_subscriptions_update on public.push_subscriptions for update to authenticated using((select auth.uid())=user_id and (select private.is_workspace_member(workspace_id))) with check((select auth.uid())=user_id and (select private.is_workspace_member(workspace_id)));
create policy push_subscriptions_delete on public.push_subscriptions for delete to authenticated using((select auth.uid())=user_id and (select private.is_workspace_member(workspace_id)));
create policy notification_deliveries_select on public.notification_deliveries for select to authenticated using((select auth.uid())=user_id and (select private.is_workspace_member(workspace_id)));
drop trigger if exists set_updated_at on public.push_subscriptions;create trigger set_updated_at before update on public.push_subscriptions for each row execute function public.set_updated_at();
commit;
